/**
 * @event 
 * @name onUdcCompleted 
 * @description UDC 완료
 */
scwin.onUdcCompleted = function () {

    scwin.globalVars();

    const codeOptions = [
        { grpCd: 'OP101', compID: 'gr_blretrieve:cntrSizeCd', useLocalCache: true },
        { grpCd: 'OP102', compID: 'gr_blretrieve:cntrTypeCd', useLocalCache: true },

        { grpCd: 'LO132', compID: 'acb_dvnRateStdRgn' },
    ];
    $c.data.setCommonCode(codeOptions, scwin.f_OnLoad);

};



/**
 * @method 
 * @name globalVars 
 * @description 전역변수선언
 */
scwin.globalVars = function () {

    // 현재일자
    scwin.toDay = $c.date.getServerDateTime('yyyyMMdd');
    scwin.onloadRetrieve = true;   //조회 여부
    scwin.hqty = 0;
    scwin.hwt = 0;
    scwin.hcbm = 0;
    scwin.hrton = 0;
    scwin.hrettl = 0;
    scwin.hsndout = 0;
    scwin.rownum = 0;
    scwin.customcheck = 0;
    scwin.msncount = 0;
    scwin.positionrow = 0;
    scwin.cntrnumber = '';
    scwin.checking = 0;
    scwin.checkHeadGrid = 0;  // 헤더 체크 여부 

};



