 * @name gr_retrieve_oneditend 
 * @description 셀의 편집이 끝난 경우 발생하며, onafteredit보다 먼저 발생
 */
scwin.gr_retrieve_oneditend = function (rowIndex, columnIndex, value) {

    let colID = this.getColumnID(columnIndex);
    // 데이터가 변경된 경우 팝업창 호출  
